<!doctype html>
<html><head><meta charset="utf-8"><title>Return Form</title><style>body{font-family:Arial,sans-serif;color:#111;margin:36px}.doc{max-width:820px;margin:auto}.head{border-bottom:2px solid #111;padding-bottom:16px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:24px 0}.box{border:1px solid #ccc;padding:12px}.sign{margin-top:80px;border-top:1px solid #111;padding-top:8px}@media print{button{display:none}}</style></head>
<body onload="window.print()"><div class="doc"><button onclick="window.print()">Print</button><div class="head"><h1>Asset Return Form</h1></div><div class="grid"><div class="box"><strong>Employee</strong><br>{{ $return->employee?->name_en }}<br>{{ $return->employee?->employee_code }}</div><div class="box"><strong>Asset</strong><br>{{ $return->asset?->asset_tag }} - {{ $return->asset?->name }}<br>Serial: {{ $return->asset?->serial_number ?: '-' }}</div><div class="box"><strong>Returned At</strong><br>{{ $return->returned_at?->format('M d, Y') }}</div><div class="box"><strong>Condition</strong><br>{{ $return->condition?->label() }}</div></div><p>{{ $return->notes }}</p><div class="sign">Receiver Signature</div></div></body></html>
